import anthropic
import json

client = anthropic.Anthropic()

RESEARCHER_SYSTEM = """
You are a research agent. Your job is to gather accurate, relevant information to answer
a research question. Use the available tools to search and read sources.

When you have gathered enough information, produce a research summary in this format:
{
  "question": "...",
  "findings": ["finding 1", "finding 2", ...],
  "confidence": 0.0-1.0,
  "gaps": ["what you could not determine", ...]
}

Do not make up information. If a source does not answer the question, list it as a gap.
"""

# Stub tools — replace with real implementations
def search(query: str) -> str:
    return json.dumps({"results": [
        {"title": "Tokyo population overview", "snippet": "Tokyo has approximately 13.96 million people in the city proper (2020 census)."},
        {"title": "Greater Tokyo Area", "snippet": "The Greater Tokyo Area, including surrounding prefectures, has over 37 million people."},
    ]})

def read_url(url: str) -> str:
    return json.dumps({"content": f"[Content from {url}]"})

RESEARCHER_TOOLS = [
    {
        "name": "search",
        "description": "Search for information on a topic.",
        "input_schema": {
            "type": "object",
            "properties": {"query": {"type": "string"}},
            "required": ["query"],
        },
    },
]

RESEARCHER_DISPATCH = {"search": search, "read_url": read_url}

def run_researcher(question: str, max_rounds: int = 5) -> dict:
    """
    Run the Researcher agent. Returns a parsed research summary dict.
    """
    messages = [{"role": "user", "content": f"Research question: {question}"}]

    for _ in range(max_rounds):
        resp = client.messages.create(
            model="claude-haiku-4-5-20251001",
            max_tokens=1024,
            system=RESEARCHER_SYSTEM,
            tools=RESEARCHER_TOOLS,
            messages=messages,
        )

        tool_calls = [b for b in resp.content if b.type == "tool_use"]
        if resp.stop_reason == "end_turn" or not tool_calls:
            # Extract final text and parse the JSON summary
            final_text = next((b.text for b in resp.content if b.type == "text"), "")
            # Strip code fences if present
            text = final_text.strip()
            if text.startswith("```"):
                lines = text.split("\n")
                text = "\n".join(lines[1:-1] if lines[-1].strip() == "```" else lines[1:])
            try:
                return json.loads(text)
            except json.JSONDecodeError:
                return {"question": question, "findings": [final_text], "confidence": 0.5, "gaps": []}

        messages.append({"role": "assistant", "content": resp.content})
        tool_results = []
        for tc in tool_calls:
            fn = RESEARCHER_DISPATCH.get(tc.name)
            result = fn(**tc.input) if fn else json.dumps({"error": f"Unknown tool: {tc.name}"})
            tool_results.append({"type": "tool_result", "tool_use_id": tc.id, "content": result})
        messages.append({"role": "user", "content": tool_results})

    return {"question": question, "findings": [], "confidence": 0.0, "gaps": ["max rounds reached"]}

# Example:
summary = run_researcher("What is the population of Tokyo?")
print(json.dumps(summary, indent=2))
