import anthropic
import json

client = anthropic.Anthropic()

def format_critic_feedback(verdict: dict) -> str:
    """
    Convert a Critic verdict into natural language feedback for the Researcher.
    """
    issues = verdict.get("issues", [])
    if not issues:
        return ""
    lines = ["A previous research attempt was rejected. Issues found:"]
    for issue in issues:
        severity = issue.get("severity", "minor")
        desc = issue.get("description", "")
        idx = issue.get("finding_index")
        if idx is not None:
            lines.append(f"  [{severity.upper()}] Finding {idx}: {desc}")
        else:
            lines.append(f"  [{severity.upper()}] {desc}")
    lines.append("Please address these issues in your new research attempt.")
    return "\n".join(lines)

def run_researcher_with_feedback(question: str, feedback: str = "") -> dict:
    """Invoke the Researcher, optionally with Critic feedback appended."""
    content = f"Research question: {question}"
    if feedback:
        content += f"\n\n{feedback}"
    # ... (same researcher loop implementation as before)
    resp = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=1024,
        system=RESEARCHER_SYSTEM,
        messages=[{"role": "user", "content": content}],
    )
    text = resp.content[0].text.strip()
    if text.startswith("```"):
        lines = text.split("\n")
        text = "\n".join(lines[1:-1] if lines[-1].strip() == "```" else lines[1:])
    try:
        return json.loads(text)
    except json.JSONDecodeError:
        return {"question": question, "findings": [text], "confidence": 0.5, "gaps": []}

